import { ipcMain, dialog, BrowserWindow } from 'electron';
import fs from 'fs/promises';
import { IPC_CHANNELS, GetCommandLogsSchema, GetCommandLogsSizeSchema, DeleteAllCommandLogsSchema, ExportCommandLogsSchema, ApiResult, CommandLog } from './types';
import { queries } from '../db';

export function registerCommandLogsHandlers() {
  // Get command logs
  ipcMain.handle(IPC_CHANNELS.COMMAND_LOGS_GET, async (_event, input): Promise<ApiResult<CommandLog[]>> => {
    try {
      const { serverId, limit } = GetCommandLogsSchema.parse(input);
      const commands = queries.getCommandsByServer(serverId, limit);
      return { success: true, data: commands };
    } catch (error) {
      console.error('Error fetching command logs:', error);
      return { success: false, error: String(error) };
    }
  });

  // Get command logs size
  ipcMain.handle(IPC_CHANNELS.COMMAND_LOGS_GET_SIZE, async (_event, input): Promise<ApiResult<number>> => {
    try {
      const { serverId } = GetCommandLogsSizeSchema.parse(input);
      const size = queries.getCommandsSize(serverId);
      return { success: true, data: size };
    } catch (error) {
      console.error('Error fetching command logs size:', error);
      return { success: false, error: String(error) };
    }
  });

  // Delete all command logs
  ipcMain.handle(IPC_CHANNELS.COMMAND_LOGS_DELETE_ALL, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const { serverId } = DeleteAllCommandLogsSchema.parse(input);
      queries.deleteAllCommands(serverId);
      return { success: true };
    } catch (error) {
      console.error('Error deleting all command logs:', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.COMMAND_LOGS_EXPORT, async (event, input): Promise<ApiResult<{ filePath: string }>> => {
    try {
      const { serverId, content, suggestedFileName } = ExportCommandLogsSchema.parse(input);
      const window = BrowserWindow.fromWebContents(event.sender);
      const defaultPath = suggestedFileName || `server-${serverId}-command-logs.json`;

      const result = await dialog.showSaveDialog(window ?? BrowserWindow.getAllWindows()[0], {
        title: 'Export Command Logs',
        defaultPath,
        filters: [
          { name: 'JSON', extensions: ['json'] },
          { name: 'All Files', extensions: ['*'] },
        ],
      });

      if (result.canceled || !result.filePath) {
        return { success: false, error: 'Export canceled' };
      }

      await fs.writeFile(result.filePath, content, 'utf-8');

      return { success: true, data: { filePath: result.filePath } };
    } catch (error) {
      console.error('Error exporting command logs:', error);
      return { success: false, error: String(error) };
    }
  });
}
